var tags = flow.get('tags') || {};
var msgs = [];

function log(msg) {
  var now = new Date().toLocaleTimeString('pt-BR');
  tags.log = tags.log || [];
  tags.log.unshift('[' + now + '] ' + msg);
  if (tags.log.length > 20) tags.log.pop();
}

// ===== MÁQUINA DE ESTADOS =====
switch(tags.estado) {

  case 'IDLE':
    if (tags.Inicio_HMI || tags.Inicia_Queima) {
      // Verifica permissivos básicos
      if (tags.iDefeito_Bool) {
        log('FALHA: Defeito ativo - sequência bloqueada');
        tags.EMERGENCIA_ALARME1 = true;
        break;
      }
      if (!tags.iSV_01_Closed) {
        log('AVISO: SV-01 não confirmada fechada');
      }
      tags.estado = 'PRE_PURGA';
      tags.step = 0;
      tags.timer_acc = 0;
      log('INÍCIO: Iniciando sequência de queima piloto');
    }
    break;

  case 'PRE_PURGA':
    // Passo 1: Abre caixa de vento / soprador
    if (tags.step === 0) {
      tags.oAciona_Soprador = true;
      tags.oCx_Vento_Out = true;
      tags.oSV_01_Abrir = false;
      tags.oSV_01_Fechar = true;
      tags.oSV_02_Abrir = false;
      tags.oSV_02_Fechar = true;
      log('PURGA: Acionando soprador e abrindo caixa de vento...');
      tags.step = 1;
      tags.timer_acc = 0;
    }
    // Simula feedback da caixa de vento após 3s
    if (tags.step === 1) {
      tags.timer_acc++;
      if (tags.timer_acc >= 3) {
        tags.iCx_Vento_Opened = true;
        tags.iCx_Vento_Closed = false;
        tags.iZS_Soprador = true;
        log('PURGA: Soprador ligado - caixa de vento ABERTA');
        tags.step = 2;
        tags.timer_acc = 0;
      }
    }
    // Aguarda tempo de purga (15s)
    if (tags.step === 2) {
      tags.timer_acc++;
      log('PURGA: Tempo de purga ' + tags.timer_acc + '/15s');
      if (tags.timer_acc >= 15) {
        tags.estado = 'ABRE_SV_GLP';
        tags.step = 0;
        tags.timer_acc = 0;
        log('PURGA: Concluída - avançando para abertura GLP');
      }
    }
    break;

  case 'ABRE_SV_GLP':
    if (tags.step === 0) {
      // Abre válvula geral GLP
      tags.oGLP_Fechada = false;
      log('GLP: Abrindo válvula geral GLP...');
      tags.step = 1;
      tags.timer_acc = 0;
    }
    if (tags.step === 1) {
      tags.timer_acc++;
      if (tags.timer_acc >= 2) {
        tags.iSV_GLP_Opened = true;
        tags.iSV_GLP_Closed = false;
        log('GLP: Válvula geral GLP ABERTA - pressão disponível');
        // Simula pressão GLP
        tags.iPIT_01_GLP_PV = 1.5 + Math.random() * 0.3;
        tags.estado = 'ABRE_SV_PILOTO';
        tags.step = 0;
        tags.timer_acc = 0;
      }
    }
    break;

  case 'ABRE_SV_PILOTO':
    if (tags.step === 0) {
      // Abre SV-01 (piloto)
      tags.oSV_01_Abrir = true;
      tags.oSV_01_Fechar = false;
      tags.oGLP_Piloto_Abrir = true;
      log('SV-01: Abrindo válvula solenóide piloto...');
      tags.step = 1;
      tags.timer_acc = 0;
    }
    if (tags.step === 1) {
      tags.timer_acc++;
      if (tags.timer_acc >= 2) {
        tags.iSV_01_Opened = true;
        tags.iSV_01_Closed = false;
        tags.SV_01_DuasSaidas = true;
        tags.iFIT_01_GLP_PV = 5.0 + Math.random() * 1.0;
        log('SV-01: ABERTA - fluxo GLP piloto: ' + tags.iFIT_01_GLP_PV.toFixed(1) + ' Nm³/h');
        tags.estado = 'IGNICAO';
        tags.step = 0;
        tags.timer_acc = 0;
      }
    }
    break;

  case 'IGNICAO':
    if (tags.step === 0) {
      tags.oAciona_Ignicao = true;
      tags.oPiloto_Acesso = true;
      log('IGNIÇÃO: Ativando transformador de ignição...');
      tags.step = 1;
      tags.timer_acc = 0;
    }
    if (tags.step === 1) {
      tags.timer_acc++;
      // Tenta ignição - confirma chama após 3s
      if (tags.timer_acc >= 3) {
        // Simula sucesso de ignição (95% de chance)
        if (Math.random() > 0.05) {
          tags.iZS_Queimador_Piloto = true;
          tags.iTIT_02_Ignicao_PV = 120.0 + Math.random() * 30;
          tags.oAciona_Ignicao = false; // Desliga ignitor
          log('IGNIÇÃO: ✓ CHAMA PILOTO CONFIRMADA - Temp ignição: ' + tags.iTIT_02_Ignicao_PV.toFixed(0) + '°C');
          tags.estado = 'PILOTO_ESTAVEL';
          tags.step = 0;
          tags.timer_acc = 0;
        } else {
          tags.oAciona_Ignicao = false;
          tags.oSV_01_Abrir = false;
          tags.oSV_01_Fechar = true;
          tags.oGLP_Piloto_Abrir = false;
          log('IGNIÇÃO: ✗ FALHA - Sem confirmação de chama. Emergência!');
          tags.EMERGENCIA_ALARME1 = true;
          tags.estado = 'FALHA';
        }
      }
    }
    break;

  case 'PILOTO_ESTAVEL':
    // Aquece o refratário com piloto
    tags.timer_acc++;
    tags.iTIT_01_Refratario_PV = Math.min(
      tags.iTIT_01_Refratario_PV + (2 + Math.random()),
      350
    );
    tags.iTIT_02_Ignicao_PV = 150 + Math.random() * 20;
    if (tags.timer_acc % 5 === 0) {
      log('PILOTO: Estável - Refratário: ' + tags.iTIT_01_Refratario_PV.toFixed(0) + '°C');
    }
    // Quando refratário atinge 300°C, abre queimador principal
    if (tags.iTIT_01_Refratario_PV >= 300 || tags.Teste_IHM) {
      log('PILOTO: Refratário pronto - abrindo queimador principal...');
      tags.estado = 'ABRE_PRINCIPAL';
      tags.step = 0;
      tags.timer_acc = 0;
    }
    break;

  case 'ABRE_PRINCIPAL':
    if (tags.step === 0) {
      tags.oSV_02_Abrir = true;
      tags.oSV_02_Fechar = false;
      tags.oGLP_Principal_Abrir = true;
      log('PRINCIPAL: Abrindo SV-02 queimador principal...');
      tags.step = 1;
      tags.timer_acc = 0;
    }
    if (tags.step === 1) {
      tags.timer_acc++;
      if (tags.timer_acc >= 2) {
        tags.iSV_02_Opened = true;
        tags.iSV_02_Closed = false;
        tags.SV_02_DuasSaidas = true;
        tags.AUX_A_SV_02 = true;
        tags.iFIT_02_Ar_PV = 25.0 + Math.random() * 5;
        log('PRINCIPAL: SV-02 ABERTA - queima principal ativa');
        tags.iZS_Queimador_Principal = true;
        tags.Inicia_Queima = true;
        tags.estado = 'QUEIMA_PLENA';
        tags.step = 0;
        tags.timer_acc = 0;
        tags.Parcial_TempoSinterizacao = 0;
      }
    }
    break;

  case 'QUEIMA_PLENA':
    tags.timer_acc++;
    tags.Parcial_TempoSinterizacao++;
    // Simula comportamento dos analógicos durante queima
    tags.iTIT_01_Refratario_PV = Math.min(tags.iTIT_01_Refratario_PV + (1 + Math.random()*2), 950);
    tags.iTIT_03_Cx_Vento_PV = Math.min(100 + tags.timer_acc * 3 + Math.random()*10, 850);
    tags.iFIT_01_GLP_PV = 8.0 + Math.random() * 2;
    tags.iFIT_02_Ar_PV = 28.0 + Math.random() * 4;
    tags.iPIT_01_GLP_PV = 1.4 + Math.random() * 0.2;
    tags.iPIT_02_Gases_PV = 0.5 + Math.random() * 0.2;
    if (tags.timer_acc % 10 === 0) {
      log('QUEIMA PLENA: Refratário ' + tags.iTIT_01_Refratario_PV.toFixed(0) + '°C | CxVento ' + tags.iTIT_03_Cx_Vento_PV.toFixed(0) + '°C | Tempo: ' + tags.Parcial_TempoSinterizacao + 's');
    }
    // Verifica alarme temperatura caixa de vento
    if (tags.iTIT_03_Cx_Vento_PV > tags.Temp_CxVento_Max) {
      log('ALARME: Temperatura caixa de vento excedida!');
      tags.EMERGENCIA_ALARME1 = true;
    }
    // Verifica fim de queima
    if (tags.Final_Queima || tags.Parcial_TempoSinterizacao >= tags.Min_TempoSinterizacao) {
      log('QUEIMA: Tempo atingido - iniciando desligamento...');
      tags.Selo_TempoSinterizacao = true;
      tags.estado = 'DESLIGAMENTO';
      tags.step = 0;
      tags.timer_acc = 0;
    }
    break;

  case 'DESLIGAMENTO':
    if (tags.step === 0) {
      // Fecha queimador principal primeiro
      tags.oSV_02_Abrir = false;
      tags.oSV_02_Fechar = true;
      tags.oGLP_Principal_Abrir = false;
      tags.AUX_F_SV_02 = true;
      log('DESLIGAMENTO: Fechando queimador principal SV-02...');
      tags.step = 1;
      tags.timer_acc = 0;
    }
    if (tags.step === 1) {
      tags.timer_acc++;
      if (tags.timer_acc >= 2) {
        tags.iSV_02_Opened = false;
        tags.iSV_02_Closed = true;
        tags.iZS_Queimador_Principal = false;
        log('DESLIGAMENTO: SV-02 fechada - desligando piloto...');
        tags.step = 2;
        tags.timer_acc = 0;
      }
    }
    if (tags.step === 2) {
      tags.timer_acc++;
      if (tags.timer_acc >= 3) {
        // Fecha piloto
        tags.oSV_01_Abrir = false;
        tags.oSV_01_Fechar = true;
        tags.oGLP_Piloto_Abrir = false;
        tags.oAciona_Ignicao = false;
        tags.step = 3;
        tags.timer_acc = 0;
        log('DESLIGAMENTO: Piloto desligado - fechando GLP geral...');
      }
    }
    if (tags.step === 3) {
      tags.timer_acc++;
      if (tags.timer_acc >= 2) {
        tags.iSV_01_Opened = false;
        tags.iSV_01_Closed = true;
        tags.iSV_GLP_Opened = false;
        tags.iSV_GLP_Closed = true;
        tags.oGLP_Fechada = true;
        tags.iZS_Queimador_Piloto = false;
        log('DESLIGAMENTO: GLP geral fechado - iniciando resfriamento...');
        tags.estado = 'RESFRIAMENTO';
        tags.step = 0;
        tags.timer_acc = 0;
      }
    }
    break;

  case 'RESFRIAMENTO':
    tags.timer_acc++;
    // Mantém soprador por tempo de resfriamento
    tags.iTIT_01_Refratario_PV = Math.max(tags.iTIT_01_Refratario_PV - (3 + Math.random()*2), 25);
    tags.iTIT_03_Cx_Vento_PV = Math.max(tags.iTIT_03_Cx_Vento_PV - (5 + Math.random()*3), 25);
    if (tags.timer_acc % 5 === 0) {
      log('RESFRIAMENTO: ' + tags.timer_acc + 's | Refratário: ' + tags.iTIT_01_Refratario_PV.toFixed(0) + '°C');
    }
    if (tags.timer_acc >= tags.Min_TempoResfriamento) {
      tags.oAciona_Soprador = false;
      tags.oCx_Vento_Out = false;
      tags.iCx_Vento_Closed = true;
      tags.iCx_Vento_Opened = false;
      tags.iZS_Soprador = false;
      tags.iFIT_01_GLP_PV = 0;
      tags.iFIT_02_Ar_PV = 0;
      tags.iPIT_01_GLP_PV = 0;
      tags.iPIT_02_Gases_PV = 0;
      tags.Inicia_Queima = false;
      tags.Final_Queima = false;
      tags.Inicio_HMI = false;
      log('RESFRIAMENTO: Concluído - Sistema PRONTO');
      tags.estado = 'IDLE';
      tags.step = 0;
      tags.timer_acc = 0;
    }
    break;

  case 'FALHA':
    // Em falha, aguarda reset
    tags.oAciona_Ignicao = false;
    if (tags.Reset_IHM || tags.Reset_Seq) {
      log('RESET: Falha reconhecida - retornando ao IDLE');
      tags.EMERGENCIA_ALARME1 = false;
      tags.iDefeito_Bool = false;
      tags.oSV_01_Abrir = false; tags.oSV_01_Fechar = true;
      tags.oSV_02_Abrir = false; tags.oSV_02_Fechar = true;
      tags.oGLP_Piloto_Abrir = false;
      tags.oGLP_Principal_Abrir = false;
      tags.iZS_Queimador_Piloto = false;
      tags.iZS_Queimador_Principal = false;
      tags.oAciona_Soprador = false;
      tags.Inicio_HMI = false;
      tags.Inicia_Queima = false;
      tags.Reset_IHM = false;
      tags.Reset_Seq = false;
      tags.estado = 'IDLE';
      tags.step = 0;
      tags.timer_acc = 0;
    }
    break;
}

flow.set('tags', tags);

// Envia para os nós de saída
return [{payload: tags}];

var tags = msg.payload;

// Estado da máquina
var corEstado = 'grey';
if (tags.estado === 'IDLE') corEstado = 'blue';
else if (tags.estado === 'FALHA') corEstado = 'red';
else if (tags.estado === 'QUEIMA_PLENA') corEstado = 'orange';
else if (tags.estado === 'PILOTO_ESTAVEL') corEstado = 'yellow';
else if (tags.estado === 'RESFRIAMENTO') corEstado = 'cyan';
else corEstado = 'green';

var msg1 = {payload: tags.estado, topic: 'estado'};
var msg2 = {payload: tags.iTIT_01_Refratario_PV, topic: 'tit01'};
var msg3 = {payload: tags.iTIT_02_Ignicao_PV, topic: 'tit02'};
var msg4 = {payload: tags.iTIT_03_Cx_Vento_PV, topic: 'tit03'};
var msg5 = {payload: tags.iFIT_01_GLP_PV, topic: 'fit01'};
var msg6 = {payload: tags.iFIT_02_Ar_PV, topic: 'fit02'};
var msg7 = {payload: tags.iPIT_01_GLP_PV, topic: 'pit01'};
var msg8 = {payload: tags.iPIT_02_Gases_PV, topic: 'pit02'};
var msg9 = {payload: tags.log.join('\n'), topic: 'log'};
var msg10 = {payload: tags.EMERGENCIA_ALARME1, topic: 'alarme'};
var msg11 = {payload: tags, topic: 'all'};
var msg12 = {payload: tags.iZS_Queimador_Piloto ? '🔥 CHAMA PILOTO ON' : '⭕ CHAMA PILOTO OFF', topic:'chama_piloto'};
var msg13 = {payload: tags.iZS_Queimador_Principal ? '🔥 PRINCIPAL ON' : '⭕ PRINCIPAL OFF', topic:'chama_principal'};
var msg14 = {payload: tags.Parcial_TempoSinterizacao, topic:'tempo_sint'};

return [[msg1, msg2, msg3, msg4, msg5, msg6, msg7, msg8, msg9, msg10, msg11, msg12, msg13, msg14]];

var tags = flow.get('tags') || {};
var cmd = msg.payload;

switch(cmd) {
  case 'iniciar':
    if (tags.estado === 'IDLE') {
      tags.Inicio_HMI = true;
      node.status({fill:'green',shape:'dot',text:'Iniciado'});
    } else {
      node.status({fill:'yellow',shape:'ring',text:'Seq. em andamento: '+tags.estado});
    }
    break;
  case 'finalizar':
    if (tags.estado === 'QUEIMA_PLENA' || tags.estado === 'PILOTO_ESTAVEL') {
      tags.Final_Queima = true;
      node.status({fill:'orange',shape:'dot',text:'Finalizando...'});
    }
    break;
  case 'reset':
    tags.Reset_IHM = true;
    tags.Reset_Seq = true;
    node.status({fill:'blue',shape:'dot',text:'Reset enviado'});
    break;
  case 'emergencia':
    tags.EMERGENCIA_ALARME1 = true;
    tags.iDefeito_Bool = true;
    tags.iZS_Emerg = true;
    tags.oSV_01_Abrir = false; tags.oSV_01_Fechar = true;
    tags.oSV_02_Abrir = false; tags.oSV_02_Fechar = true;
    tags.oGLP_Piloto_Abrir = false;
    tags.oGLP_Principal_Abrir = false;
    tags.oAciona_Ignicao = false;
    tags.estado = 'FALHA';
    node.status({fill:'red',shape:'dot',text:'EMERGÊNCIA!'});
    break;
  case 'teste_principal':
    if (tags.estado === 'PILOTO_ESTAVEL') {
      tags.Teste_IHM = true;
      node.status({fill:'blue',shape:'dot',text:'Forçando principal'});
    }
    break;
}

flow.set('tags', tags);
return null;

var tags = flow.get('tags') || {};
tags.iDefeito_Bool = true;
tags.EMERGENCIA_ALARME1 = true;
flow.set('tags', tags);
return null;
